import React from "react";
import HomeScreen from "./HomeScreen";
import GoalsScreen from "./GoalsScreen";
import LoansScreen from "./LoansScreen";
import ProfileScreen from "./ProfileScreen";

export default function Dashboard({ currentTab, setCurrentTab, ...props }) {
  // ===== Choose which screen to show =====
  const renderScreen = () => {
    switch (currentTab) {
      case "Home":
        return <HomeScreen {...props} />;
      case "Goals":
        return <GoalsScreen goals={props.goals} />;
      case "Loans":
        return <LoansScreen loans={props.loans} />;
      case "Profile":
        return <ProfileScreen user={props.user} />;
      default:
        return <HomeScreen {...props} />;
    }
  };

  return (
    <div className="flex flex-col h-screen">
      {/* Main content */}
      <div className="flex-1 overflow-auto">{renderScreen()}</div>

      {/* Bottom navigation bar */}
      <nav className="bg-white border-t border-gray-200 flex justify-around py-2 sticky bottom-0 z-10">
        {["Home", "Goals", "Loans", "Profile"].map((tab) => (
          <button
            key={tab}
            onClick={() => setCurrentTab(tab)}
            className={`flex flex-col items-center text-sm ${
              currentTab === tab ? "text-emerald-600 font-bold" : "text-gray-500"
            }`}
          >
            {/* You can replace these spans with icons from lucide-react */}
            <span>{tab}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}
